<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>{{ $title ?? 'MAPS2U' }}</title><link rel="stylesheet" href="{{ asset('css/app.css') }}"></head><body><div class="site-shell">@include('components.header')<div class="app-body {{ auth()->check() ? 'authenticated' : 'guest-body' }}">@auth @include('components.sidebar')<button type="button" class="sidebar-backdrop" data-sidebar-close aria-label="Close navigation"></button>@endauth <main class="content-shell">@include('components.flash')@yield('content')</main></div>@include('components.footer')</div><script>const updateClock=()=>{document.querySelectorAll('[data-live-clock]').forEach((el)=>{el.textContent=new Date().toLocaleString('en-MY',{weekday:'long',year:'numeric',month:'long',day:'numeric',hour:'2-digit',minute:'2-digit',second:'2-digit'});});};updateClock();setInterval(updateClock,1000);const openSidebar=()=>document.body.classList.add('sidebar-open');const closeSidebar=()=>document.body.classList.remove('sidebar-open');document.querySelectorAll('[data-sidebar-toggle]').forEach((button)=>{button.addEventListener('click',()=>document.body.classList.toggle('sidebar-open'));});document.querySelectorAll('[data-sidebar-close]').forEach((button)=>{button.addEventListener('click',closeSidebar);});window.addEventListener('resize',()=>{if(window.innerWidth>980)closeSidebar();});document.addEventListener('keydown',(event)=>{if(event.key==='Escape')closeSidebar();});document.querySelectorAll('.sidebar a').forEach((link)=>{link.addEventListener('click',()=>{if(window.innerWidth<=980)closeSidebar();});});document.querySelectorAll('[data-profile-toggle]').forEach((button)=>{button.addEventListener('click',()=>button.parentElement.classList.toggle('open'));});document.querySelectorAll('[data-bell-toggle]').forEach((button)=>{button.addEventListener('click',()=>button.parentElement.classList.toggle('open'));});document.querySelectorAll('[data-delete-confirm]').forEach((form)=>{form.addEventListener('submit',(event)=>{if(!confirm(form.dataset.deleteConfirm||'Confirm delete?'))event.preventDefault();});});</script></body></html>
